app.post('/dev/push-file', async (req, res) => {
  try {
    const GITHUB_TOKEN = process.env.GITHUB_TOKEN;
    if (!GITHUB_TOKEN) return res.status(500).json({ error: 'GITHUB_TOKEN not set in env' });

    const { path, content, message, encoding = 'utf8' } = req.body;
    if (!path || !content || !message)
      return res.status(400).json({ error: 'path, content, message required' });

    const REPO = 'cmovate/interactive-report';
    const apiUrl = `https://api.github.com/repos/${REPO}/contents/${path}`;

    // Get current SHA (if file exists)
    let sha;
    const getRes = await fetch(apiUrl, {
      headers: { Authorization: `token ${GITHUB_TOKEN}`, Accept: 'application/vnd.github.v3+json' }
    });
    if (getRes.ok) {
      const existing = await getRes.json();
      sha = existing.sha;
    }

    // Encode content
    const encoded = encoding === 'base64'
      ? content
      : Buffer.from(content, 'utf8').toString('base64');

    // Push
    const putBody = { message, content: encoded };
    if (sha) putBody.sha = sha;

    const putRes = await fetch(apiUrl, {
      method: 'PUT',
      headers: {
        Authorization: `token ${GITHUB_TOKEN}`,
        'Content-Type': 'application/json',
        Accept: 'application/vnd.github.v3+json'
      },
      body: JSON.stringify(putBody)
    });
    const result = await putRes.json();
    if (!putRes.ok) return res.status(putRes.status).json({ error: result.message || 'GitHub push failed' });

    console.log(`[DevPush] ${path} ÃÂÃÂÃÂÃÂ¢ÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂ ${result.commit?.sha?.slice(0,7)}`);
    res.json({ success: true, commit: result.commit?.sha?.slice(0,7), path });
  } catch (err) {
    res.status(500).json({ error: err.message });
  }
});


