function msgColsCreate() {
  let sql = '';
  for (let i = 1; i <= MAX_MSG_SLOTS; i++) {
    sql += `      msg_${i}_text    TEXT,\n`;
    sql += `      msg_${i}_variant VARCHAR(1),\n`;
  }
  return sql;
}

