// POST /dev/push-file { path, content (base64 or utf8), message, encoding? }
// Uses GITHUB_TOKEN env var. Only enabled when GITHUB_TOKEN is set.
app.post('/dev/push-file', express.json({ limit: '5mb' }), async (req, res) => {
  const token = process.env.GITHUB_TOKEN;
  if (!token) return res.status(403).json({ error: 'GITHUB_TOKEN not configured' });

  const { path: filePath, content, message, encoding = 'utf8' } = req.body;
  if (!filePath || !content || !message)
    return res.status(400).json({ error: 'path, content, message required' });

  const REPO = 'cmovate/interactive-report';
  const apiBase = 'https://api.github.com';
  const headers = {
    'Authorization': 'token ' + token,
    'Content-Type': 'application/json',
    'Accept': 'application/vnd.github.v3+json'
  };

  try {
    // Step 1: Get current SHA (if file exists)
    let sha;
    try {
      const getRes = await fetch(apiBase + '/repos/' + REPO + '/contents/' + filePath, { headers });
      if (getRes.ok) {
        const existing = await getRes.json();
        sha = existing.sha;
      }
    } catch (_) {}

    // Step 2: Encode content as base64
    const b64Content = encoding === 'base64' ? content
      : Buffer.from(content, 'utf8').toString('base64');

    // Step 3: Push
    const body = { message, content: b64Content };
    if (sha) body.sha = sha;

    const putRes = await fetch(apiBase + '/repos/' + REPO + '/contents/' + filePath, {
      method: 'PUT', headers, body: JSON.stringify(body)
    });
    const result = await putRes.json();

    if (!putRes.ok) return res.status(putRes.status).json({ error: result.message || 'Push failed' });

    console.log('[Dev] Pushed ' + filePath + ' ÃÂÃÂ¢ÃÂÃÂÃÂÃÂ ' + result.commit?.sha?.slice(0,7));
    res.json({ success: true, commit: result.commit?.sha?.slice(0,7), path: filePath });
  } catch (err) {
    res.status(500).json({ error: err.message });
  }
});

